<script setup lang="ts">
import {onMounted,ref} from 'vue';import {RouterLink} from 'vue-router';import {fetchCircle,fetchCirclePosts,type PublicCircle} from '@/services/circle';import type {CommunityPost} from '@/types/community'
const props=defineProps<{circleId:number}>(),circle=ref<PublicCircle|null>(null),posts=ref<CommunityPost[]>([]),error=ref('');onMounted(async()=>{try{[circle.value,posts.value]=await Promise.all([fetchCircle(props.circleId),fetchCirclePosts(props.circleId).then(r=>r.list)])}catch(e){error.value=e instanceof Error?e.message:'圈子加载失败'}})
</script>
<template><section class="page-section"><p v-if="error" class="feedback is-error">{{error}}</p><template v-if="circle"><header class="circle-hero"><p class="eyebrow">{{circle.region}} · 官方圈子</p><h1>{{circle.name}}</h1><p>{{circle.description}}</p><strong>{{circle.memberCount}} 位成员 · {{circle.postCount}} 篇帖子</strong></header><div class="rank-list"><RouterLink v-for="post in posts" :key="post.id" :to="`/community/posts/${post.id}`" class="content-card rank-item"><div class="rank-item__body"><p class="eyebrow"><RouterLink :to="`/users/${post.userId}`">{{post.userName}}</RouterLink> · {{post.createdAt}}</p><h2>{{post.title}}</h2><p>{{post.content}}</p><small>喜欢 {{post.likeCount}} · 评论 {{post.commentCount}}</small></div></RouterLink></div></template></section></template>
<style scoped>.circle-hero{padding:34px;border-radius:30px;background:linear-gradient(135deg,#ffe4d4,#fff9f4);box-shadow:0 18px 44px rgba(90,45,24,.1);margin-bottom:24px}.circle-hero h1{font-size:38px;margin:8px 0}.circle-hero strong{font-variant-numeric:tabular-nums}</style>
